  const classified = customers.map((c) => {
    const result = classifyCustomer(c);
    return {
      ...c,
      _rulePriority: result.level,
      _ruleSubType: result.subType || null,
      _ruleReasons: result.reasons,
      _needAI: result.needAI,
      _ruleConfidence: result.confidence || 'deterministic',
    };
  });

  const stats = {
    total: classified.length,
    byPriority: {},
    needAI: classified.filter((c) => c._needAI).length,
    deterministic: classified.filter((c) => !c._needAI).length,
  };

  for (const c of classified) {
    stats.byPriority[c._rulePriority] = (stats.byPriority[c._rulePriority] || 0) + 1;
  }

  return {
    classifiedAt: new Date().toISOString(),
    source: data.processedAt || data.capturedAt || 'unknown',
    stats,
    customers: classified,
  };
}

// ====== CLI ======

function findLatestCleaned() {
  const files = fs.readdirSync(DATA_DIR).filter((f) => f.startsWith('cleaned_') && f.endsWith('.json'));
  if (files.length === 0) return null;
